import { useState, useRef } from 'react';
import { Link, useNavigate } from 'react-router-dom';

import { addRow } from '../../crud/crud';
import { handleLogout } from '../../consts/handleLogout';

import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function AddCrossroadRoadSing() {
    const [road_sing_id, setRoadSingID] = useState('');
    const [crossroad_id, setCrossroadID] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const submitCrossroadRoadSing = async (e) => {
        const headers = {
            'Content-Type': 'multipart/form-data',
            'Accept': 'application/json'
        }
        e.preventDefault();
        const crossroad_road_sing = { road_sing_id, crossroad_id };
        const add_crossroad_road_sing = addRow('/crossroads/roads/sings', crossroad_road_sing, headers);

        if (add_crossroad_road_sing.status === 201) {
            setRoadSingID('');
            setCrossroadID('');
            navigate('/crossroads/roads/sings');
        }
    };

    return (
        <div>
            <nav className="navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0">
                <div className="container-fluid py-2">
                    <Link className="navbar-brand fs-3 fw-bold" to="/main">Дорожное хозяйство</Link>
                    <div class="btn-group">
                        <button type="button" class="btn btn-info">Пользователь</button>
                        <button type="button" class="btn btn-info dropdown-toggle dropdown-toggle-split" data-bs-toggle="dropdown" aria-expanded="false">
                            <span class="visually-hidden">Переключатель выпадающего списка</span>
                        </button>
                        <ul class="dropdown-menu">
                            <li>
                                <a class="dropdown-item">
                                    <button
                                        onClick={() => { handleLogout(); navigate('/login') }}
                                        className='dropdown-item'
                                        disabled={loading}
                                    >
                                        {loading ? (
                                            <>
                                                <span className='spinner'></span>
                                                Выход...
                                            </>
                                        ) : 'Выйти'}
                                    </button>
                                </a>
                            </li>
                        </ul>
                    </div>
                </div>
            </nav>
            <form className='container' onSubmit={submitCrossroadRoadSing}>
                <h1>Создание знака на перекрестке</h1>
                <div className='mb-3'>
                    <lable className='form-label'>ID дорожного знака на дороге</lable>
                    <input 
                        type='text'
                        name='road_sing_id' 
                        value={road_sing_id.road_sing_id} 
                        onChange={(e) => setRoadSingID(e.target.value)}
                        className='form-input'  
                        placeholder='ID дорожного знака на дороге'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>ID перекрестка</lable>
                    <input 
                        type='text'
                        name='crossroad_id' 
                        value={crossroad_id.crossroad_id} 
                        onChange={(e) => setCrossroadID(e.target.value)}
                        className='form-input'  
                        placeholder='ID перекрестка'
                        required  
                    />
                </div>
                <button 
                    type='submit' 
                    className='btn btn-primary'
                >
                    Добавить
                </button>
                <button 
                    type='submit' 
                    className='btn btn-danger' 
                    onClick={() => navigate('/crossroads/roads/sings')}
                >
                    Назад
                </button>
            </form>
        </div>
    )
};

export default AddCrossroadRoadSing;
